//! # SpectralManifest from PCAB sidecar (synergy consumer)
//!
//! Reads a `.pca` sidecar (`PCAB` magic) emitted by
//! `standing_wave_pinning::write_pca_bases` and derives per-layer
//! `SpectralManifest`s by selecting the top-k *coordinate-aligned*
//! dimensions weighted by the principal components.
//!
//! Why this matters: the magnitude-based manifest in `manifest_real.rs`
//! picks dimensions by raw weight L2 norm, which captures static
//! structure but not the calibrated activation flow. The PCAB basis was
//! fit by power-iteration over real per-layer activations during a
//! probe run — the empirical handoff measured 50–100× KL improvement
//! over random orthogonal at the same coverage. Same calibration data,
//! two consumers: their forward-pass routing + my storage manifest.
//!
//! ## Coordinate selection from a non-aligned basis
//!
//! The PCAB stores each principal component as a length-d vector — they
//! are NOT axis-aligned in general. Our format requires axis-aligned
//! `standing_indices: Vec<u32>` (length k, indices into [0, d)). We
//! project: for each coordinate `j`, score it by the L2 magnitude
//! across all k basis components:
//!
//! ```text
//! score[j] = sqrt(Σ_i basis[i, j]²)   for i in [0, k)
//! ```
//!
//! The top-k coordinates by `score[j]` become `standing_indices`. This
//! captures "which raw dimensions carry the most variance under the
//! calibrated principal-component basis" — a strict improvement over
//! the magnitude-only baseline.
//!
//! ## Doesn't touch the standing-wave-pinning module
//!
//! Per the cross-territory handoff: this module READS the PCAB format
//! via `crate::standing_wave_pinning::read_pca_bases` only. No edits to
//! that file or any of the routing/calibration binaries.

use super::format::{DenseTensor, SpectralManifest};
use super::manifest_real::{column_abs_max, select_with_outlier_reserve};
use crate::standing_wave_pinning::read_pca_bases;

/// Errors emitted while building manifests from a PCAB sidecar.
#[derive(Debug)]
pub enum PcaManifestError {
    Io(std::io::Error),
    NoBasisForLayer(usize),
    LayerOutOfRange { layer: usize, num_layers: usize },
}

impl From<std::io::Error> for PcaManifestError {
    fn from(e: std::io::Error) -> Self {
        PcaManifestError::Io(e)
    }
}

impl std::fmt::Display for PcaManifestError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            PcaManifestError::Io(e) => write!(f, "pca read failed: {}", e),
            PcaManifestError::NoBasisForLayer(l) => {
                write!(f, "no PCA basis fitted for layer {}", l)
            }
            PcaManifestError::LayerOutOfRange { layer, num_layers } => {
                write!(
                    f,
                    "layer {} out of range (num_layers={})",
                    layer, num_layers
                )
            }
        }
    }
}

impl std::error::Error for PcaManifestError {}

/// In-memory PCAB cache. Indexed by layer index → (k, mean, basis).
pub struct PcaBasis {
    pub hidden_dim: usize,
    pub num_layers: usize,
    /// `(layer_idx, k, mean, basis)` per fitted layer. Layers without a
    /// fitted basis are absent (or have k=0).
    pub bases: Vec<(usize, usize, Vec<f32>, Vec<f32>)>,
}

impl PcaBasis {
    /// Load a `.pca` sidecar produced by the standing-wave PCA fitter.
    pub fn open(path: &str) -> Result<Self, PcaManifestError> {
        let (hidden_dim, num_layers, bases) = read_pca_bases(path)?;
        Ok(PcaBasis {
            hidden_dim,
            num_layers,
            bases,
        })
    }

    /// Look up a layer's `(k, mean, basis)` if a basis was fitted.
    pub fn layer(&self, layer_idx: usize) -> Option<(usize, &[f32], &[f32])> {
        for (l, k, mean, basis) in &self.bases {
            if *l == layer_idx && *k > 0 {
                return Some((*k, mean.as_slice(), basis.as_slice()));
            }
        }
        None
    }

    /// Destructive lookup: removes the basis for `layer_idx` from the cache
    /// and returns it. Used by the encoder to free several GB of RAM
    /// during 70B re-encodes once a layer's manifest is built.
    pub fn take_layer(&mut self, layer_idx: usize) -> Option<(usize, Vec<f32>, Vec<f32>)> {
        let pos = self.bases.iter().position(|(l, _, _, _)| *l == layer_idx)?;
        let (_, k, mean, basis) = self.bases.remove(pos);
        if k > 0 {
            Some((k, mean, basis))
        } else {
            None
        }
    }

    /// Iterate over `(layer_idx, k)` pairs for layers that have a basis.
    pub fn fitted_layers(&self) -> impl Iterator<Item = (usize, usize)> + '_ {
        self.bases
            .iter()
            .filter(|(_, k, _, _)| *k > 0)
            .map(|(l, k, _, _)| (*l, *k))
    }
}

/// Per-coordinate L2 magnitude across the principal components.
/// `score[j] = sqrt(Σ_i basis[i, j]²)` for `j in [0, d)`. Returned in
/// the same order as the input dimensions.
pub fn coordinate_scores(basis: &[f32], k: usize, d: usize) -> Vec<f32> {
    debug_assert_eq!(basis.len(), k * d);
    let mut scores = vec![0.0f32; d];
    for component in 0..k {
        let row_off = component * d;
        for j in 0..d {
            let v = basis[row_off + j];
            scores[j] += v * v;
        }
    }
    for s in scores.iter_mut() {
        *s = s.sqrt();
    }
    scores
}

/// Build a `SpectralManifest` for one layer by selecting the top-k
/// coordinates with the highest [`coordinate_scores`].
///
/// Equivalent to [`manifest_for_layer_with_outliers`] called with
/// `outlier_tensors = None` — kept as a thin wrapper for backward
/// compatibility and for tests that do not exercise the outlier
/// reserve.
pub fn manifest_for_layer(
    layer_idx: usize,
    num_layers: usize,
    hidden_dim: usize,
    basis_info: (usize, &[f32], &[f32]),
    coverage: f32,
) -> Result<SpectralManifest, PcaManifestError> {
    manifest_for_layer_with_outliers(
        layer_idx, num_layers, hidden_dim, basis_info, coverage, None,
    )
}

/// Build a `SpectralManifest` for one layer by selecting standing
/// coordinates with [`coordinate_scores`] as the primary score, then
/// (optionally) reserving a fraction of the budget for columns that
/// carry extreme absolute weight values across the supplied tensors.
///
/// `outlier_tensors` should be the layer's Q/K/V (and optionally FFN)
/// dense weight tensors when available. Each tensor contributes
/// `column_abs_max` per column, taken element-wise across the slice
/// (so a single ±72 entry in any tensor lifts that column's outlier
/// score). `None` falls back to score-only selection (the legacy
/// behavior; equivalent to PCA before the `e839d9dd` fidelity-check
/// fix).
///
/// The output `coverage` may differ slightly from the requested ratio
/// because k is rounded with banker-style integer arithmetic
/// (matching `manifest::stub_first_k_manifest`).
pub fn manifest_for_layer_with_outliers(
    layer_idx: usize,
    num_layers: usize,
    hidden_dim: usize,
    basis_info: (usize, &[f32], &[f32]),
    coverage: f32,
    outlier_tensors: Option<&[&DenseTensor]>,
) -> Result<SpectralManifest, PcaManifestError> {
    if layer_idx >= num_layers {
        return Err(PcaManifestError::LayerOutOfRange {
            layer: layer_idx,
            num_layers,
        });
    }
    let (k_pc, _mean, basis) = basis_info;
    let d = hidden_dim;
    let scores = coordinate_scores(basis, k_pc, d);

    // Same integer-math k derivation as the rest of the manifest API.
    let coverage = coverage.clamp(0.0, 1.0);
    let k_target = ((d as u64 * (coverage * 1_000.0).round() as u64 + 500) / 1_000) as u32;
    let k_target = (k_target as usize).min(d);

    // Per-coordinate outlier score: max over supplied tensors of
    // `column_abs_max`. Columns past a tensor's `cols` (GQA / FFN tail)
    // contribute 0 — they only count for tensors that actually reach
    // that index. Empty when no tensors supplied → equivalent to a
    // zero abs_max vector, in which case `select_with_outlier_reserve`
    // will fall back to score-only ordering for the reserve slots.
    let abs_max = match outlier_tensors {
        Some(tensors) if !tensors.is_empty() => {
            let mut combined = vec![0.0f32; d];
            for t in tensors {
                let am = column_abs_max(t);
                for (c, slot) in combined.iter_mut().enumerate() {
                    if let Some(&v) = am.get(c) {
                        if v > *slot {
                            *slot = v;
                        }
                    }
                }
            }
            combined
        }
        _ => vec![0.0f32; d],
    };

    // Score-driven primary + abs-max outlier reserve. Falls back to
    // score-only when abs_max is identically zero (legacy behavior).
    let standing: Vec<u32> =
        select_with_outlier_reserve(d as u32, k_target as u32, &scores, &abs_max);

    // Normalize amplitudes to [0, 1] off the max selected score (using
    // the original PCA score, NOT the outlier metric — amplitudes
    // measure how much PCA energy each chosen column carries).
    let amps_raw: Vec<f32> = standing.iter().map(|&i| scores[i as usize]).collect();
    let max_amp = amps_raw.iter().cloned().fold(0.0f32, f32::max);
    let amplitudes: Vec<f32> = if max_amp > 0.0 {
        amps_raw.iter().map(|a| a / max_amp).collect()
    } else {
        vec![0.0; standing.len()]
    };

    let phase_alignment = vec![0.7; standing.len()];
    Ok(SpectralManifest {
        d: d as u32,
        k: standing.len() as u32,
        standing_indices: standing,
        amplitudes,
        // No phase information from the PCA fit alone; default to a
        // moderate value so downstream graded encoders allocate
        // intermediate bit budgets. The real phase signal lives in the
        // attention QKV decomposition (separate calibration probe).
        phase_alignment,
    })
}

/// Build manifests for every fitted layer at the requested coverage.
/// Returns one `(layer_idx, manifest)` per layer that had a basis;
/// layers without a basis are silently skipped (caller decides whether
/// to fall back to the magnitude-based manifest for those).
pub fn manifests_for_all_fitted_layers(
    pca: &PcaBasis,
    coverage: f32,
) -> Vec<(u32, SpectralManifest)> {
    let mut out = Vec::new();
    for (layer_idx, _) in pca.fitted_layers() {
        if let Some(info) = pca.layer(layer_idx) {
            if let Ok(manifest) =
                manifest_for_layer(layer_idx, pca.num_layers, pca.hidden_dim, info, coverage)
            {
                out.push((layer_idx as u32, manifest));
            }
        }
    }
    out
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::standing_wave_pinning::write_pca_bases;

    fn synthetic_basis(k: usize, d: usize) -> Vec<f32> {
        // k orthogonal-ish bases with a clear top-k coordinate concentration.
        // Component i emphasizes coordinates {i, i+k, i+2k, …}.
        let mut v = vec![0.0f32; k * d];
        for component in 0..k {
            let row = component * d;
            for j in (component..d).step_by(k) {
                v[row + j] = 1.0;
            }
        }
        v
    }

    fn temp_path(tag: &str) -> String {
        std::env::temp_dir()
            .join(format!("pca-manifest-{}-{}.pca", tag, std::process::id()))
            .to_string_lossy()
            .into_owned()
    }

    #[test]
    fn coordinate_scores_length_matches_d() {
        let d = 64;
        let k = 8;
        let basis = synthetic_basis(k, d);
        let scores = coordinate_scores(&basis, k, d);
        assert_eq!(scores.len(), d);
    }

    #[test]
    fn manifest_from_pca_round_trip() {
        let d = 100;
        let k_pc = 10;
        let p = temp_path("rt");
        let mean = vec![0.0f32; d];
        let basis = synthetic_basis(k_pc, d);
        write_pca_bases(&p, d, 1, &[(0, k_pc, mean, basis)]).unwrap();

        let pca = PcaBasis::open(&p).unwrap();
        assert_eq!(pca.hidden_dim, d);
        assert_eq!(pca.num_layers, 1);

        // Coverage 0.30 → k = 30 indices.
        let info = pca.layer(0).unwrap();
        let m = manifest_for_layer(0, pca.num_layers, pca.hidden_dim, info, 0.30).unwrap();
        assert!(m.is_well_formed());
        assert_eq!(m.k, 30);
        assert_eq!(m.standing_indices.len(), 30);
        // All indices are sorted ascending and inside [0, d).
        for w in m.standing_indices.windows(2) {
            assert!(w[0] < w[1], "indices not sorted: {:?}", w);
        }
        for &i in &m.standing_indices {
            assert!(i < m.d);
        }
        let _ = std::fs::remove_file(&p);
    }

    #[test]
    fn manifest_layer_out_of_range_errors() {
        let d = 32;
        let p = temp_path("oor");
        write_pca_bases(&p, d, 2, &[(0, 4, vec![0.0; d], synthetic_basis(4, d))]).unwrap();
        let pca = PcaBasis::open(&p).unwrap();
        let err = manifest_for_layer(99, pca.num_layers, pca.hidden_dim, (0, &[], &[]), 0.30);
        assert!(matches!(err, Err(PcaManifestError::LayerOutOfRange { .. })));
        let _ = std::fs::remove_file(&p);
    }

    #[test]
    fn manifest_no_basis_for_layer_errors() {
        let d = 32;
        let p = temp_path("nobasis");
        // Layer 1 has k=0 (no fitted basis).
        write_pca_bases(
            &p,
            d,
            2,
            &[
                (0, 4, vec![0.0; d], synthetic_basis(4, d)),
                (1, 0, vec![], vec![]),
            ],
        )
        .unwrap();
        let pca = PcaBasis::open(&p).unwrap();
        let err = if let Some(info) = pca.layer(1) {
            manifest_for_layer(1, pca.num_layers, pca.hidden_dim, info, 0.30)
        } else {
            Err(PcaManifestError::NoBasisForLayer(1))
        };
        assert!(matches!(err, Err(PcaManifestError::NoBasisForLayer(1))));
        let _ = std::fs::remove_file(&p);
    }

    /// PCA-path twin of `manifest_real::outlier_preservation_keeps_extreme_column`.
    /// PCA score favors a different set than abs-max → outlier columns
    /// must still survive when supplied as `outlier_tensors`. Cloud
    /// probe `e839d9dd` motivation.
    #[test]
    fn pca_outlier_preservation_keeps_extreme_column() {
        let d = 64usize;
        let k_pc = 4usize;
        // Synthetic basis: components emphasize coordinates 0..16 only
        // (component i hits {i, i+4, i+8, …} like `synthetic_basis`,
        // restricted to the first 16 dims). PCA score will rank cols
        // 0..16 highest.
        let mut basis = vec![0.0f32; k_pc * d];
        for component in 0..k_pc {
            let row = component * d;
            for j in (component..16).step_by(k_pc) {
                basis[row + j] = 1.0;
            }
        }
        let mean = vec![0.0f32; d];

        // Outlier tensor: a single ±72 entry in column 32, zeros elsewhere.
        // PCA score for col 32 is 0 — without the outlier reserve it
        // would never be selected.
        let outlier_col = 32u32;
        let rows = 8u32;
        let mut data = vec![0.0f32; rows as usize * d];
        data[outlier_col as usize] = 72.0; // row 0, col 32
        let outlier_tensor = DenseTensor {
            rows,
            cols: d as u32,
            data,
        };
        let tensors = [&outlier_tensor];

        let info = (k_pc, mean.as_slice(), basis.as_slice());
        // coverage 0.25 of d=64 → k=16
        let manifest = manifest_for_layer_with_outliers(0, 1, d, info, 0.25, Some(&tensors))
            .expect("manifest construction");
        assert_eq!(manifest.k, 16);
        assert!(
            manifest.standing_indices.contains(&outlier_col),
            "outlier column {} (abs-max=72) must survive PCA-path manifest construction; got {:?}",
            outlier_col,
            manifest.standing_indices
        );
        // Indices are sorted ascending per the manifest contract.
        for w in manifest.standing_indices.windows(2) {
            assert!(w[0] < w[1]);
        }
        assert!(manifest.is_well_formed());
    }

    /// PCA-path: when `outlier_tensors` is None, the manifest still
    /// has the requested coverage and shape. (Strict equivalence with
    /// the pre-fix selector is not promised — when abs_max is
    /// identically zero, the outlier-reserve slots fall back to
    /// index-ascending order rather than continuing the score order,
    /// so the chosen set may shift slightly. Callers that need the
    /// exact pre-fix selection can still call the legacy
    /// `manifest_for_layer`, which now routes through the same
    /// reserve path.)
    #[test]
    fn pca_outlier_none_yields_well_formed_manifest() {
        let d = 64usize;
        let k_pc = 8usize;
        let basis = synthetic_basis(k_pc, d);
        let mean = vec![0.0f32; d];
        let info = (k_pc, mean.as_slice(), basis.as_slice());

        let with_outliers = manifest_for_layer_with_outliers(0, 1, d, info, 0.25, None).unwrap();
        assert_eq!(with_outliers.k, 16);
        assert_eq!(with_outliers.standing_indices.len(), 16);
        for w in with_outliers.standing_indices.windows(2) {
            assert!(w[0] < w[1]);
        }
        assert!(with_outliers.is_well_formed());
    }

    #[test]
    fn fitted_layers_skips_k_zero() {
        let d = 16;
        let p = temp_path("fitted");
        write_pca_bases(
            &p,
            d,
            3,
            &[
                (0, 2, vec![0.0; d], synthetic_basis(2, d)),
                (1, 0, vec![], vec![]),
                (2, 4, vec![0.0; d], synthetic_basis(4, d)),
            ],
        )
        .unwrap();
        let pca = PcaBasis::open(&p).unwrap();
        let fitted: Vec<(usize, usize)> = pca.fitted_layers().collect();
        assert_eq!(fitted, vec![(0, 2), (2, 4)]);
        let _ = std::fs::remove_file(&p);
    }
}
